147→const distancePointToSegment = (px, py, x1, y1, x2, y2) => {
148→    const dx = x2 - x1;
149→    const dy = y2 - y1;
150→    if(dx === 0 && dy === 0){
151→        return Math.hypot(px - x1, py - y1);
152→    }
153→
154→    const t = clamp(((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy), 0, 1);
155→    const cx = x1 + t * dx;
156→    const cy = y1 + t * dy;
157→    return Math.hypot(px - cx, py - cy);
158→};
